// Assemble retrieved chunks into a citation-marked context block for Claude
const config = $('Set Search Configuration').item.json;
const raw = $json;
const matches = Array.isArray(raw) ? raw : (raw.data || raw.matches || []);

if (matches.length === 0) {
  return [{
    json: {
      question: config.question,
      sessionId: config.sessionId,
      askedAt: config.askedAt,
      businessName: config.businessName,
      contextBlock: '(No matching documents found in the knowledge base.)',
      sources: [],
      noContext: true
    }
  }];
}

const chunks = matches.slice(0, config.topK || 5).map((m, i) => {
  const id = (m.id != null ? m.id : ('chunk_' + (i + 1))).toString();
  const score = Number(m.similarity || m.score || 0);
  const content = (m.content || m.text || '').toString();
  const meta = m.metadata || {};
  return { id, score, content, metadata: meta };
});

const contextBlock = chunks.map(c => `[${c.id}]\n${c.content}`).join('\n\n---\n\n');

return [{
  json: {
    question: config.question,
    sessionId: config.sessionId,
    askedAt: config.askedAt,
    businessName: config.businessName,
    contextBlock,
    sources: chunks.map(c => ({ id: c.id, score: c.score, title: c.metadata.title || c.metadata.source || '' })),
    noContext: false
  }
}];

