// Parse Claude's JSON, attach source metadata for cited chunks, build final response
const ctx = $('Build Context from Matches').item.json;
const raw = $json.content?.[0]?.text || '{}';

let parsed = {
  answer: 'AI response could not be parsed.',
  citations: [],
  confident: false
};

try {
  const cleaned = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed.answer = 'AI returned malformed JSON: ' + raw.slice(0, 200);
}

const citedSources = (Array.isArray(parsed.citations) ? parsed.citations : [])
  .map(id => ctx.sources.find(s => s.id.toString() === id.toString()))
  .filter(Boolean);

return [{
  json: {
    question: ctx.question,
    sessionId: ctx.sessionId,
    askedAt: ctx.askedAt,
    answer: parsed.answer,
    confident: parsed.confident === true,
    sources: citedSources,
    allRetrievedSources: ctx.sources,
    noContext: ctx.noContext
  }
}];
